#!/usr/bin/env node
/**
 * Generates a VS Code CSS Custom Data file (schema v1.1) from the published
 * SLASHED API index, so `--sf-*` tokens autocomplete with descriptions and
 * default values in any editor that supports the format.
 *
 * Run: npm run docs:vscode-data   (or: node scripts/gen-vscode-custom-data.js)
 *
 * Reads docs/api-index.json (already regenerated by gen-api-index.js earlier
 * in the `npm run docs` pipeline) so this never hand-maintains its own token
 * list — it can only drift if api-index.json itself is stale.
 *
 * Ships in the published npm package inside dist/ (the build output
 * directory), alongside the CSS bundles — see README for the
 * .vscode/settings.json wiring snippet.
 */

import fs   from 'node:fs';
import path from 'node:path';

const ROOT = path.resolve(import.meta.dirname, '..');
const API_INDEX = path.join(ROOT, 'docs', 'api-index.json');
const OUT = path.join(ROOT, 'dist', 'css-custom-data.json');

// INTERNAL tokens aren't part of the supported API — don't surface them in
// editor autocomplete. PUBLIC and PUBLIC-ADVANCED are both consumer-facing.
const INCLUDED_TIERS = new Set(['PUBLIC', 'PUBLIC-ADVANCED']);

function buildDescription(entry) {
  const parts = [entry.description || ''];
  if (entry.value) parts.push(`Default: \`${entry.value}\``);
  if (entry.tier === 'PUBLIC-ADVANCED') parts.push('(advanced token)');
  return parts.join('\n\n');
}

function main() {
  const { entries } = JSON.parse(fs.readFileSync(API_INDEX, 'utf8'));

  const properties = entries
    .filter(e => e.type === 'token' && INCLUDED_TIERS.has(e.tier))
    .map(e => ({
      name: e.name,
      description: buildDescription(e),
      syntax: e.syntax || '*',
    }))
    .sort((a, b) => a.name.localeCompare(b.name));

  const customData = {
    version: 1.1,
    properties,
  };

  fs.mkdirSync(path.dirname(OUT), { recursive: true });
  fs.writeFileSync(OUT, JSON.stringify(customData, null, 2) + '\n', 'utf8');
  console.log(`[vscode-data] → dist/css-custom-data.json (${properties.length} tokens)`);
}

main();
